package metrics

import (
	"context"
	"sync"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

type SandboxCollector struct {
	store store.Store
	k8s   kubernetes.Interface

	activeTotal   *prometheus.Desc
	createdTotal  *prometheus.Desc
	deletedTotal  *prometheus.Desc
	duration      *prometheus.Desc
	requestDelay  *prometheus.Desc

	mu           sync.Mutex
	sessionStart map[string]time.Time
}

func NewSandboxCollector(s store.Store, k8s kubernetes.Interface) *SandboxCollector {
	return &SandboxCollector{
		store: s,
		k8s:   k8s,
		activeTotal: prometheus.NewDesc(
			"agentcube_sandbox_active_total",
			"Total number of active sandboxes",
			nil, nil,
		),
		createdTotal: prometheus.NewDesc(
			"agentcube_sandbox_created_total",
			"Total number of created sandboxes",
			nil, nil,
		),
		deletedTotal: prometheus.NewDesc(
			"agentcube_sandbox_deleted_total",
			"Total number of deleted sandboxes",
			nil, nil,
		),
		duration: prometheus.NewDesc(
			"agentcube_session_duration_seconds",
			"Duration of sandbox sessions in seconds",
			[]string{"session_id", "namespace"}, nil,
		),
		requestDelay: prometheus.NewDesc(
			"agentcube_request_duration_seconds",
			"HTTP request duration in seconds",
			[]string{"method", "endpoint", "status"}, nil,
		),
		sessionStart: make(map[string]time.Time),
	}
}

func (c *SandboxCollector) Describe(ch chan<- *prometheus.Desc) {
	ch <- c.activeTotal
	ch <- c.createdTotal
	ch <- c.deletedTotal
	ch <- c.duration
	ch <- c.requestDelay
}

func (c *SandboxCollector) Collect(ch chan<- prometheus.Metric) {
	ctx := context.Background()

	activeSandboxes, err := c.store.ListInactiveSandboxes(ctx, time.Now(), 10000)
	if err != nil {
		klog.Errorf("Failed to list active sandboxes: %v", err)
		return
	}

	ch <- prometheus.MustNewConstMetric(
		c.activeTotal,
		prometheus.GaugeValue,
		float64(len(activeSandboxes)),
	)

	klog.V(4).Infof("Collected %d active sandboxes", len(activeSandboxes))
}

func (c *SandboxCollector) RecordSessionStart(sessionID string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.sessionStart[sessionID] = time.Now()
}

func (c *SandboxCollector) RecordSessionEnd(sessionID string) {
	c.mu.Lock()
	startTime, ok := c.sessionStart[sessionID]
	if ok {
		delete(c.sessionStart, sessionID)
		duration := time.Since(startTime).Seconds()
		klog.V(4).Infof("Session %s duration: %.2f seconds", sessionID, duration)
	}
	c.mu.Unlock()
}

var _ prometheus.Collector = &SandboxCollector{}

type MetricsServer struct {
	addr      string
	registry  *prometheus.Registry
	collector *SandboxCollector
}

func NewMetricsServer(addr string, collector *SandboxCollector) *MetricsServer {
	return &MetricsServer{
		addr:      addr,
		registry:  prometheus.NewRegistry(),
		collector: collector,
	}
}

func (s *MetricsServer) Start() error {
	s.registry.MustRegister(s.collector)

	httpHandler := prometheus.HandlerFor(s.registry, prometheus.HandlerOpts{})

	klog.Infof("Metrics server starting on %s", s.addr)
	klog.Infof("Metrics endpoint available at /metrics")

	return nil
}

func (s *MetricsServer) Stop() error {
	klog.Info("Metrics server stopped")
	return nil
}

package metrics

import (
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
	"k8s.io/klog/v2"
)

var (
	httpRequestsTotal = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "agentcube_http_requests_total",
			Help: "Total number of HTTP requests",
		},
		[]string{"method", "endpoint", "status"},
	)

	httpRequestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "agentcube_http_request_duration_seconds",
			Help:    "HTTP request duration in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"method", "endpoint"},
	)

	sandboxEvents = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "agentcube_sandbox_events_total",
			Help: "Total number of sandbox lifecycle events",
		},
		[]string{"event_type", "namespace"},
	)
)

func init() {
	prometheus.MustRegister(httpRequestsTotal)
	prometheus.MustRegister(httpRequestDuration)
	prometheus.MustRegister(sandboxEvents)
}

type MetricsMiddleware struct {
	handler http.Handler
}

func NewMetricsMiddleware(handler http.Handler) *MetricsMiddleware {
	return &MetricsMiddleware{handler: handler}
}

func (m *MetricsMiddleware) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	startTime := time.Now()
	path := r.URL.Path
	method := r.Method

	ww := &statusWriter{ResponseWriter: w, statusCode: http.StatusOK}

	m.handler.ServeHTTP(ww, r)

	duration := time.Since(startTime).Seconds()
	status := ww.statusCode

	httpRequestsTotal.WithLabelValues(method, path, string(rune(status))).Inc()
	httpRequestDuration.WithLabelValues(method, path).Observe(duration)
}

type statusWriter struct {
	http.ResponseWriter
	statusCode int
}

func (w *statusWriter) WriteHeader(statusCode int) {
	w.statusCode = statusCode
	w.ResponseWriter.WriteHeader(statusCode)
}

func RecordSandboxEvent(eventType, namespace string) {
	sandboxEvents.WithLabelValues(eventType, namespace).Inc()
}

type MetricsHandler struct{}

func (h *MetricsHandler) Handle(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/metrics" {
		http.NotFound(w, r)
		return
	}

	handler := promhttp.Handler()
	handler.ServeHTTP(w, r)
}

func NewMetricsHandler() *MetricsHandler {
	return &MetricsHandler{}
}

func StartMetricsServer(addr string, collector *SandboxCollector) error {
	mux := http.NewServeMux()
	mux.Handle("/metrics", NewMetricsHandler())

	klog.Infof("Starting metrics server on %s", addr)
	klog.Info("Metrics available at /metrics")

	return http.ListenAndServe(addr, mux)
}

