package main

import (
	"flag"
	"fmt"
	"net/http"

	"github.com/volcano-sh/agentcube/pkg/metrics"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(flag.CommandLine)
	flag.Parse()

	port := flag.String("port", "9090", "Port to listen on")
	storeType := flag.String("store-type", "redis", "Store type: redis, valkey")
	redisAddr := flag.String("redis-addr", "localhost:6379", "Redis address")
	kubeconfig := flag.String("kubeconfig", "", "Path to kubeconfig file")

	klog.Infof("Starting metrics exporter")
	klog.Infof("Store type: %s", *storeType)
	klog.Infof("Redis address: %s", *redisAddr)

	s, err := createStore(*storeType, *redisAddr)
	if err != nil {
		klog.Exitf("Failed to create store: %v", err)
	}
	defer s.Close()

	k8sClient, err := createKubernetesClient(*kubeconfig)
	if err != nil {
		klog.Warningf("Failed to create k8s client: %v (metrics may be limited)", err)
	}

	collector := metrics.NewSandboxCollector(s, k8sClient)
	metricsServer := metrics.NewMetricsServer(":"+*port, collector)

	if err := metricsServer.Start(); err != nil {
		klog.Exitf("Failed to start metrics server: %v", err)
	}

	addr := fmt.Sprintf(":%s", *port)
	if err := http.ListenAndServe(addr, nil); err != nil {
		klog.Exitf("Server error: %v", err)
	}
}

func createStore(storeType, addr string) (store.Store, error) {
	switch storeType {
	case "redis":
		return store.NewRedisStore(addr)
	case "valkey":
		return store.NewValkeyStore(addr)
	default:
		return nil, fmt.Errorf("unsupported store type: %s", storeType)
	}
}

func createKubernetesClient(kubeconfig string) (interface{}, error) {
	return nil, nil
}

