package rbac

import (
	"context"
	"fmt"
	"sync"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

type TenantManager struct {
	k8sClient   kubernetes.Interface
	tenantCache TenantCache
	mu          sync.RWMutex
}

type TenantCache struct {
	tenants map[string]*Tenant
	mu      sync.RWMutex
}

type Tenant struct {
	Name               string
	Namespace          string
	ResourceQuota     ResourceQuota
	SandboxLimit      int
	CreatedAt          metav1.Time
}

type ResourceQuota struct {
	CPU    resource.Quantity
	Memory resource.Quantity
	Pods   int64
}

const (
	TenantNamespacePrefix = "tenant-"
	DefaultCPUQuota     = "4"
	DefaultMemoryQuota  = "8Gi"
	DefaultPodQuota     = "10"
	DefaultSandboxLimit = 10
)

func NewTenantManager(k8sClient kubernetes.Interface) *TenantManager {
	return &TenantManager{
		k8sClient: k8sClient,
		tenantCache: TenantCache{
			tenants: make(map[string]*Tenant),
		},
	}
}

func (tm *TenantManager) CreateTenant(ctx context.Context, name string) (*Tenant, error) {
	tm.mu.Lock()
	defer tm.mu.Unlock()

	namespace := TenantNamespacePrefix + name

	ns := &corev1.Namespace{
		ObjectMeta: metav1.ObjectMeta{
			Name: namespace,
			Labels: map[string]string{
				"agentcube.io/tenant":    name,
				"agentcube.io/managed":  "true",
			},
		},
	}

	_, err := tm.k8sClient.CoreV1().Namespaces().Create(ctx, ns, metav1.CreateOptions{})
	if err != nil {
		klog.Errorf("Failed to create namespace for tenant %s: %v", name, err)
		return nil, fmt.Errorf("failed to create tenant namespace: %w", err)
	}

	quota := corev1.ResourceQuotaSpec{
		Hard: corev1.ResourceList{
			corev1.ResourceCPU:    resource.MustParse(DefaultCPUQuota),
			corev1.ResourceMemory: resource.MustParse(DefaultMemoryQuota),
			"pods":                resource.MustParse(DefaultPodQuota),
		},
	}

	quotaObj := &corev1.ResourceQuota{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "tenant-quota",
			Namespace: namespace,
		},
		Spec: quota,
	}

	_, err = tm.k8sClient.CoreV1().ResourceQuotas(namespace).Create(ctx, quotaObj, metav1.CreateOptions{})
	if err != nil {
		klog.Warningf("Failed to create resource quota for tenant %s: %v", name, err)
	}

	tenant := &Tenant{
		Name:      name,
		Namespace: namespace,
		ResourceQuota: ResourceQuota{
			CPU:    *resource.NewQuantity(4, resource.DecimalExponent),
			Memory: *resource.NewQuantity(8*1024*1024*1024, resource.BinarySI),
			Pods:   10,
		},
		SandboxLimit: DefaultSandboxLimit,
		CreatedAt:    metav1.Now(),
	}

	tm.tenantCache.tenants[name] = tenant

	klog.Infof("Created tenant %s with namespace %s", name, namespace)
	return tenant, nil
}

func (tm *TenantManager) GetTenant(ctx context.Context, name string) (*Tenant, error) {
	tm.mu.RLock()
	defer tm.mu.RUnlock()

	if tenant, ok := tm.tenantCache.tenants[name]; ok {
		return tenant, nil
	}

	namespace := TenantNamespacePrefix + name
	_, err := tm.k8sClient.CoreV1().Namespaces().Get(ctx, namespace, metav1.GetOptions{})
	if err != nil {
		return nil, fmt.Errorf("tenant not found: %s", name)
	}

	tenant := &Tenant{
		Name:      name,
		Namespace: namespace,
		ResourceQuota: ResourceQuota{
			CPU:    *resource.NewQuantity(4, resource.DecimalExponent),
			Memory: *resource.NewQuantity(8*1024*1024*1024, resource.BinarySI),
			Pods:   10,
		},
		SandboxLimit: DefaultSandboxLimit,
	}

	tm.tenantCache.tenants[name] = tenant
	return tenant, nil
}

func (tm *TenantManager) DeleteTenant(ctx context.Context, name string) error {
	tm.mu.Lock()
	defer tm.mu.Unlock()

	namespace := TenantNamespacePrefix + name

	err := tm.k8sClient.CoreV1().Namespaces().Delete(ctx, namespace, metav1.DeleteOptions{})
	if err != nil {
		return fmt.Errorf("failed to delete tenant: %w", err)
	}

	delete(tm.tenantCache.tenants, name)
	klog.Infof("Deleted tenant %s", name)
	return nil
}

func (tm *TenantManager) ListTenants(ctx context.Context) ([]*Tenant, error) {
	tm.mu.RLock()
	defer tm.mu.RUnlock()

	tenants := make([]*Tenant, 0, len(tm.tenantCache.tenants))
	for _, tenant := range tm.tenantCache.tenants {
		tenants = append(tenants, tenant)
	}

	return tenants, nil
}

func (tm *TenantManager) GetTenantByNamespace(ctx context.Context, namespace string) (*Tenant, error) {
	tm.mu.RLock()
	defer tm.mu.RUnlock()

	for _, tenant := range tm.tenantCache.tenants {
		if tenant.Namespace == namespace {
			return tenant, nil
		}
	}

	ns, err := tm.k8sClient.CoreV1().Namespaces().Get(ctx, namespace, metav1.GetOptions{})
	if err != nil {
		return nil, fmt.Errorf("namespace not found: %s", namespace)
	}

	tenantName, ok := ns.Labels["agentcube.io/tenant"]
	if !ok {
		return nil, fmt.Errorf("namespace %s is not a tenant namespace", namespace)
	}

	return tm.GetTenant(ctx, tenantName)
}

package rbac

import (
	"context"
	"fmt"
	"sync"

	authenticationv1 "k8s.io/api/authentication/v1"
	"k8s.io/klog/v2"
)

type PolicyEngine struct {
	mu           sync.RWMutex
	policies     map[string]*AccessPolicy
	roleBindings map[string][]RoleBinding
}

type AccessPolicy struct {
	Tenant   string
	Role     Role
	Subjects []string
}

type RoleBinding struct {
	Tenant  string
	Role    Role
	Subject string
}

type Role string

const (
	RoleAdmin     Role = "admin"
	RoleDeveloper Role = "developer"
	RoleViewer    Role = "viewer"
)

type AccessDecision struct {
	Allowed bool
	Reason  string
}

func NewPolicyEngine() *PolicyEngine {
	engine := &PolicyEngine{
		policies:     make(map[string]*AccessPolicy),
		roleBindings: make(map[string][]RoleBinding),
	}
	engine.initializeDefaultPolicies()
	return engine
}

func (pe *PolicyEngine) initializeDefaultPolicies() {
	pe.policies["admin"] = &AccessPolicy{
		Role: RoleAdmin,
	}
	pe.policies["developer"] = &AccessPolicy{
		Role: RoleDeveloper,
	}
	pe.policies["viewer"] = &AccessPolicy{
		Role: RoleViewer,
	}
}

func (pe *PolicyEngine) Evaluate(ctx context.Context, user string, action Action, resource Resource) *AccessDecision {
	pe.mu.RLock()
	defer pe.mu.RUnlock()

	tenant := resource.Tenant
	roleBindings := pe.roleBindings[tenant]

	var userRole Role
	for _, binding := range roleBindings {
		if binding.Subject == user {
			userRole = binding.Role
			break
		}
	}

	if userRole == "" {
		klog.Warningf("No role binding found for user %s in tenant %s", user, tenant)
		return &AccessDecision{Allowed: false, Reason: "no role binding"}
	}

	switch action {
	case ActionCreate:
		if userRole == RoleAdmin || userRole == RoleDeveloper {
			return &AccessDecision{Allowed: true, Reason: "role permits creation"}
		}
	case ActionRead:
		return &AccessDecision{Allowed: true, Reason: "role permits read"}
	case ActionUpdate:
		if userRole == RoleAdmin || userRole == RoleDeveloper {
			return &AccessDecision{Allowed: true, Reason: "role permits update"}
		}
	case ActionDelete:
		if userRole == RoleAdmin {
			return &AccessDecision{Allowed: true, Reason: "role permits deletion"}
		}
	}

	return &AccessDecision{Allowed: false, Reason: fmt.Sprintf("role %s does not permit %s", userRole, action)}
}

func (pe *PolicyEngine) BindRole(ctx context.Context, tenant, subject string, role Role) error {
	pe.mu.Lock()
	defer pe.mu.Unlock()

	binding := RoleBinding{
		Tenant:  tenant,
		Role:    role,
		Subject: subject,
	}

	pe.roleBindings[tenant] = append(pe.roleBindings[tenant], binding)

	klog.Infof("Bound role %s to subject %s in tenant %s", role, subject, tenant)
	return nil
}

func (pe *PolicyEngine) UnbindRole(ctx context.Context, tenant, subject string) error {
	pe.mu.Lock()
	defer pe.mu.Unlock()

	bindings := pe.roleBindings[tenant]
	for i, binding := range bindings {
		if binding.Subject == subject {
			pe.roleBindings[tenant] = append(bindings[:i], bindings[i+1:]...)
			klog.Infof("Unbound subject %s from tenant %s", subject, tenant)
			return nil
		}
	}

	return fmt.Errorf("no binding found for subject %s in tenant %s", subject, tenant)
}

func (pe *PolicyEngine) GetRole(ctx context.Context, tenant, subject string) (Role, error) {
	pe.mu.RLock()
	defer pe.mu.RUnlock()

	bindings := pe.roleBindings[tenant]
	for _, binding := range bindings {
		if binding.Subject == subject {
			return binding.Role, nil
		}
	}

	return "", fmt.Errorf("no role found for subject %s in tenant %s", subject, tenant)
}

type Action string

const (
	ActionCreate Action = "create"
	ActionRead   Action = "read"
	ActionUpdate Action = "update"
	ActionDelete Action = "delete"
)

type Resource struct {
	Tenant    string
	Namespace string
	Name      string
	Kind      string
}

func (pe *PolicyEngine) AuthenticateToken(ctx context.Context, token string) (*authenticationv1.TokenReview, error) {
	tr := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	klog.V(4).Infof("Token authentication not fully implemented - returning anonymous")
	tr.Status = authenticationv1.TokenReviewStatus{
		Authenticated: false,
		User: authenticationv1.UserInfo{
			Username: "anonymous",
		},
	}

	return tr, nil
}

package rbac

import (
	"context"
	"fmt"
	"sync"
	"time"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

type QuotaController struct {
	k8sClient  kubernetes.Interface
	tenantMgr  *TenantManager
	quotas     map[string]*TenantQuota
	mu         sync.RWMutex
	interval   time.Duration
	stopCh     chan struct{}
}

type TenantQuota struct {
	Tenant       string
	CPU          resource.Quantity
	Memory       resource.Quantity
	Pods         int64
	UsedCPU      resource.Quantity
	UsedMemory   resource.Quantity
	UsedPods     int64
	SandboxLimit int
	UsedSandbox  int
}

func NewQuotaController(k8sClient kubernetes.Interface, tenantMgr *TenantManager) *QuotaController {
	return &QuotaController{
		k8sClient: k8sClient,
		tenantMgr: tenantMgr,
		quotas:    make(map[string]*TenantQuota),
		interval:  30 * time.Second,
		stopCh:    make(chan struct{}),
	}
}

func (qc *QuotaController) Start(ctx context.Context) error {
	klog.Info("Starting quota controller")

	ticker := time.NewTicker(qc.interval)
	go func() {
		for {
			select {
			case <-ticker.C:
				qc.reconcile(ctx)
			case <-qc.stopCh:
				ticker.Stop()
				return
			case <-ctx.Done():
				ticker.Stop()
				return
			}
		}
	}()

	return nil
}

func (qc *QuotaController) Stop() error {
	close(qc.stopCh)
	klog.Info("Quota controller stopped")
	return nil
}

func (qc *QuotaController) reconcile(ctx context.Context) {
	tenants, err := qc.tenantMgr.ListTenants(ctx)
	if err != nil {
		klog.Errorf("Failed to list tenants: %v", err)
		return
	}

	for _, tenant := range tenants {
		if err := qc.syncQuota(ctx, tenant); err != nil {
			klog.Errorf("Failed to sync quota for tenant %s: %v", tenant.Name, err)
		}
	}
}

func (qc *QuotaController) syncQuota(ctx context.Context, tenant *Tenant) error {
	quota, err := qc.k8sClient.CoreV1().ResourceQuotas(tenant.Namespace).Get(ctx, "tenant-quota", metav1.GetOptions{})
	if err != nil {
		return fmt.Errorf("failed to get quota: %w", err)
	}

	qc.mu.Lock()
	defer qc.mu.Unlock()

	q := &TenantQuota{
		Tenant:       tenant.Name,
		CPU:          tenant.ResourceQuota.CPU,
		Memory:       tenant.ResourceQuota.Memory,
		Pods:         tenant.ResourceQuota.Pods,
		SandboxLimit: tenant.SandboxLimit,
	}

	if hard, ok := quota.Spec.Hard[corev1.ResourceCPU]; ok {
		q.CPU = hard
	}
	if hard, ok := quota.Spec.Hard[corev1.ResourceMemory]; ok {
		q.Memory = hard
	}
	if hard, ok := quota.Spec.Hard["pods"]; ok {
		q.Pods = hard.Value()
	}

	used := quota.Status.Used
	if usedCPU, ok := used[corev1.ResourceCPU]; ok {
		q.UsedCPU = usedCPU
	}
	if usedMem, ok := used[corev1.ResourceMemory]; ok {
		q.UsedMemory = usedMem
	}
	if usedPods, ok := used["pods"]; ok {
		q.UsedPods = usedPods.Value()
	}

	qc.quotas[tenant.Name] = q
	klog.V(4).Infof("Synced quota for tenant %s: CPU %s/%s, Memory %s/%s, Pods %d/%d",
		tenant.Name, q.UsedCPU.String(), q.CPU.String(), q.UsedMemory.String(), q.Memory.String(), q.UsedPods, q.Pods)

	return nil
}

func (qc *QuotaController) CheckQuota(ctx context.Context, tenant string, cpu, memory resource.Quantity) error {
	qc.mu.RLock()
	defer qc.mu.RUnlock()

	quota, ok := qc.quotas[tenant]
	if !ok {
		return fmt.Errorf("quota not found for tenant %s", tenant)
	}

	newCPU := quota.UsedCPU.Add(cpu)
	newMemory := quota.UsedMemory.Add(memory)

	if newCPU.Cmp(quota.CPU) > 0 {
		return fmt.Errorf("CPU quota exceeded: requested %s, available %s", cpu.String(), quota.CPU.Sub(quota.UsedCPU).String())
	}

	if newMemory.Cmp(quota.Memory) > 0 {
		return fmt.Errorf("memory quota exceeded: requested %s, available %s", memory.String(), quota.Memory.Sub(quota.UsedMemory).String())
	}

	if quota.UsedPods+1 > quota.Pods {
		return fmt.Errorf("pod quota exceeded: current %d, limit %d", quota.UsedPods, quota.Pods)
	}

	return nil
}

func (qc *QuotaController) CheckSandboxLimit(ctx context.Context, tenant string) error {
	qc.mu.RLock()
	defer qc.mu.RUnlock()

	quota, ok := qc.quotas[tenant]
	if !ok {
		return nil
	}

	if quota.UsedSandbox >= quota.SandboxLimit {
		return fmt.Errorf("sandbox limit exceeded: current %d, limit %d", quota.UsedSandbox, quota.SandboxLimit)
	}

	return nil
}

func (qc *QuotaController) IncrementUsage(ctx context.Context, tenant string, cpu, memory resource.Quantity) {
	qc.mu.Lock()
	defer qc.mu.Unlock()

	if quota, ok := qc.quotas[tenant]; ok {
		quota.UsedCPU.Add(cpu)
		quota.UsedMemory.Add(memory)
		quota.UsedPods++
		quota.UsedSandbox++
	}
}

func (qc *QuotaController) DecrementUsage(ctx context.Context, tenant string, cpu, memory resource.Quantity) {
	qc.mu.Lock()
	defer qc.mu.Unlock()

	if quota, ok := qc.quotas[tenant]; ok {
		quota.UsedCPU.Sub(cpu)
		quota.UsedMemory.Sub(memory)
		quota.UsedPods--
		quota.UsedSandbox--
	}
}

func (qc *QuotaController) GetQuota(ctx context.Context, tenant string) (*TenantQuota, error) {
	qc.mu.RLock()
	defer qc.mu.RUnlock()

	quota, ok := qc.quotas[tenant]
	if !ok {
		return nil, fmt.Errorf("quota not found for tenant %s", tenant)
	}

	return quota, nil
}

