	return func(c *gin.Context) {
		ctx := c.Request.Context()

		namespace := c.GetHeader("X-Tenant-Namespace")
		if namespace == "" {
			namespace = c.Param("namespace")
		}

		if namespace == "" {
			c.Next()
			return
		}

		tenant, err := tenantMgr.GetTenantByNamespace(ctx, namespace)
		if err != nil {
			klog.Warningf("Failed to get tenant for namespace %s: %v", namespace, err)
			c.Next()
			return
		}

		c.Set("tenant", tenant)
		c.Set("tenant-name", tenant.Name)
		c.Next()
	}
}

