		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, tenant)
}

func (h *TenantHandler) DeleteTenant(c *gin.Context) {
	ctx := c.Request.Context()
	name := c.Param("name")

	if err := h.tenantMgr.DeleteTenant(ctx, name); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "tenant deleted"})
}

func (h *TenantHandler) BindRole(c *gin.Context) {
	ctx := c.Request.Context()
	tenant := c.Param("name")

	var req struct {
		Subject string `json:"subject" binding:"required"`
		Role    string `json:"role" binding:"required"`
	}
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	role := rbac.Role(req.Role)
	if err := h.policyEng.BindRole(ctx, tenant, req.Subject, role); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "role bound"})
}

func (h *TenantHandler) UnbindRole(c *gin.Context) {
	ctx := c.Request.Context()
	tenant := c.Param("name")
	subject := c.Param("subject")

	if err := h.policyEng.UnbindRole(ctx, tenant, subject); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "role unbound"})
}

func (h *TenantHandler) GetQuota(c *gin.Context) {
	ctx := c.Request.Context()
	name := c.Param("name")

	quota, err := h.quotaCtrl.GetQuota(ctx, name)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, quota)
}

func TenantMiddleware(tenantMgr *rbac.TenantManager) gin.HandlerFunc {
	return func(c *gin.Context) {
		ctx := c.Request.Context()

		namespace := c.GetHeader("X-Tenant-Namespace")
		if namespace == "" {
			namespace = c.Param("namespace")
		}

		if namespace == "" {
			c.Next()
			return
		}

		tenant, err := tenantMgr.GetTenantByNamespace(ctx, namespace)
		if err != nil {
			klog.Warningf("Failed to get tenant for namespace %s: %v", namespace, err)
			c.Next()
			return
		}

		c.Set("tenant", tenant)
		c.Set("tenant-name", tenant.Name)
		c.Next()
	}
}

