package validation

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"

	agentv1 "github.com/volcano-sh/agentcube/pkg/apis/runtime/v1alpha1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/serializer"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/webhook/admission"
)

type AgentRuntimeValidator struct {
	decoder *admission.Decoder
}

func NewAgentRuntimeValidator() *AgentRuntimeValidator {
	return &AgentRuntimeValidator{}
}

func (v *AgentRuntimeValidator) Handle(ctx context.Context, req admission.Request) admission.Response {
	ar := &agentv1.AgentRuntime{}

	if err := json.Unmarshal(req.Object.Raw, ar); err != nil {
		return admission.Errored(http.StatusBadRequest, err)
	}

	if err := v.validate(ctx, ar); err != nil {
		return admission.Denied(err.Error())
	}

	return admission.Allowed("validation passed")
}

func (v *AgentRuntimeValidator) validate(ctx context.Context, ar *agentv1.AgentRuntime) error {
	if ar.Name == "" {
		return fmt.Errorf("AgentRuntime name is required")
	}

	if ar.Spec.Image == "" {
		return fmt.Errorf("AgentRuntime spec.image is required")
	}

	for i, ep := range ar.Spec.EntryPoints {
		if ep.Name == "" {
			return fmt.Errorf("entry point %d name is required", i)
		}
		if ep.Port <= 0 || ep.Port > 65535 {
			return fmt.Errorf("entry point %d has invalid port: %d", i, ep.Port)
		}
	}

	klog.V(4).Infof("AgentRuntime %s validation passed", ar.Name)
	return nil
}

func (v *AgentRuntimeValidator) InjectDecoder(d *admission.Decoder) error {
	v.decoder = d
	return nil
}

var _ admission.Handler = &AgentRuntimeValidator{}
var _ admission.DecoderInjector = &AgentRuntimeValidator{}

func ValidateAgentRuntime(raw []byte) error {
	ar := &agentv1.AgentRuntime{}
	scheme := runtime.NewScheme()
	if err := agentv1.AddToScheme(scheme); err != nil {
		return err
	}

	decoder := serializer.NewCodecFactory(scheme).UniversalDecoder()
	_, _, err := decoder.Decode(raw, nil, ar)
	if err != nil {
		return err
	}

	if ar.Name == "" {
		return fmt.Errorf("name is required")
	}

	if ar.Spec.Image == "" {
		return fmt.Errorf("image is required")
	}

	return nil
}

