)

type CodeInterpreterValidator struct {
	decoder *admission.Decoder
}

func NewCodeInterpreterValidator() *CodeInterpreterValidator {
	return &CodeInterpreterValidator{}
}

func (v *CodeInterpreterValidator) Handle(ctx context.Context, req admission.Request) admission.Response {
	ci := &codeinterpreterv1.CodeInterpreter{}

	if err := json.Unmarshal(req.Object.Raw, ci); err != nil {
		return admission.Errored(http.StatusBadRequest, err)
	}

	if err := v.validate(ctx, ci); err != nil {
		return admission.Denied(err.Error())
	}

	return admission.Allowed("validation passed")
}

func (v *CodeInterpreterValidator) validate(ctx context.Context, ci *codeinterpreterv1.CodeInterpreter) error {
	if ci.Name == "" {
		return fmt.Errorf("CodeInterpreter name is required")
	}

	spec := ci.Spec

	if spec.RuntimeClassName == "" {
		return fmt.Errorf("runtime class name is required")
	}

	if spec.Image == "" {
		return fmt.Errorf("image is required")
	}

	if spec.WarmPoolSize < 0 {
		return fmt.Errorf("warm pool size must be non-negative")
	}

	if spec.WarmPoolSize > 100 {
		return fmt.Errorf("warm pool size too large: max 100")
	}

	for _, port := range spec.Ports {
		if port.ContainerPort <= 0 || port.ContainerPort > 65535 {
			return fmt.Errorf("invalid port: %d", port.ContainerPort)
		}
	}

	if spec.Resources != nil {
		cpu := spec.Resources.Limits[corev1.ResourceCPU]
		if cpu.IsZero() {
			return fmt.Errorf("CPU limit is required")
		}
		memory := spec.Resources.Limits[corev1.ResourceMemory]
		if memory.IsZero() {
			return fmt.Errorf("memory limit is required")
		}
	}

	klog.V(4).Infof("CodeInterpreter %s validation passed", ci.Name)
	return nil
}

func (v *CodeInterpreterValidator) InjectDecoder(d *admission.Decoder) error {
	v.decoder = d
	return nil
}

