	addr      string
	certFile  string
	keyFile   string
	agentVal  *validation.AgentRuntimeValidator
	ciVal     *validation.CodeInterpreterValidator
	mutator   *mutation.DefaultsMutator
	mux       *http.ServeMux
}

func NewServer(addr, certFile, keyFile string) *Server {
	return &Server{
		addr:     addr,
		certFile: certFile,
		keyFile:  keyFile,
		agentVal: validation.NewAgentRuntimeValidator(),
		ciVal:    validation.NewCodeInterpreterValidator(),
		mutator:  mutation.NewDefaultsMutator(),
		mux:      http.NewServeMux(),
	}
}

func (s *Server) Register() {
	s.mux.Handle("/validate-agent-runtime", &webhook.Admission{Handler: s.agentVal})
	s.mux.Handle("/validate-code-interpreter", &webhook.Admission{Handler: s.ciVal})
	s.mux.Handle("/mutate-defaults", &webhook.Admission{Handler: s.mutator})

	klog.Info("Registered webhook paths:")
	klog.Info("  - /validate-agent-runtime")
	klog.Info("  - /validate-code-interpreter")
	klog.Info("  - /mutate-defaults")
}

func (s *Server) Start() error {
	s.Register()

	server := &http.Server{
		Addr:    s.addr,
		Handler: s.mux,
	}

	go func() {
		klog.Infof("Starting webhook server on %s", s.addr)
		if s.certFile != "" && s.keyFile != "" {
			if err := server.ListenAndServeTLS(s.certFile, s.keyFile); err != nil && err != http.ErrServerClosed {
				klog.Errorf("Webhook server error: %v", err)
			}
		} else {
			if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				klog.Errorf("Webhook server error: %v", err)
			}
		}
	}()

	return nil
}

func (s *Server) Stop(ctx context.Context) error {
	klog.Info("Stopping webhook server")

	shutdownCtx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	server := &http.Server{
		Addr:    s.addr,
		Handler: s.mux,
	}

	if err := server.Shutdown(shutdownCtx); err != nil {
		return fmt.Errorf("failed to shutdown webhook server: %w", err)
	}

	return nil
}

func RunWebhookServer(ctx context.Context) error {
	addr := getEnv("WEBHOOK_ADDR", ":9443")
	certFile := getEnv("WEBHOOK_CERT_FILE", "")
	keyFile := getEnv("WEBHOOK_KEY_FILE", "")

	server := NewServer(addr, certFile, keyFile)

	if err := server.Start(); err != nil {
		return err
	}

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	select {
	case <-sigCh:
		klog.Info("Received shutdown signal")
	case <-ctx.Done():
		klog.Info("Context cancelled")
	}

	return server.Stop(ctx)
}

func getEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

func CreateSecureServer(addr string, cert []byte, key []byte) *http.Server {
	certPEM := string(cert)
	keyPEM := string(key)

	server := &http.Server{
		Addr: addr,
		TLSConfig: &tls.Config{
			MinVersion: tls.VersionTLS12,
		},
	}

	_ = certPEM
	_ = keyPEM

	return server
}

func GetWebhookConfig() map[string]interface{} {
	return map[string]interface{}{
		"clientConfig": map[string]interface{}{
			"caBundle": "",
		},
		"rules": []map[string]interface{}{
			{
				"operations": []string{"CREATE", "UPDATE"},
				"apiGroups":   []string{""},
				"apiVersions": []string{"v1"},
				"resources":   []string{"pods"},
			},
		},
		"failurePolicy": "Fail",
		"sideEffects":  "None",
		"timeout":      "10s",
	}
}

