package templates

import (
	"fmt"
	"sync"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/resource"
)

type TemplateStore struct {
	templates map[string]*SandboxTemplate
	mu        sync.RWMutex
}

type SandboxTemplate struct {
	Name               string                       `json:"name"`
	Version            string                       `json:"version"`
	Description        string                       `json:"description"`
	RuntimeClassName   string                       `json:"runtime_class_name,omitempty"`
	Image              string                       `json:"image"`
	ImagePullSecrets   []string                     `json:"image_pull_secrets,omitempty"`
	Environment        []corev1.EnvVar              `json:"environment,omitempty"`
	Resources          *corev1.ResourceRequirements `json:"resources,omitempty"`
	Command            []string                     `json:"command,omitempty"`
	Args               []string                     `json:"args,omitempty"`
	Labels             map[string]string            `json:"labels,omitempty"`
	Annotations        map[string]string            `json:"annotations,omitempty"`
}

func NewTemplateStore() *TemplateStore {
	store := &TemplateStore{
		templates: make(map[string]*SandboxTemplate),
	}
	store.loadBuiltInTemplates()
	return store
}

func (ts *TemplateStore) loadBuiltInTemplates() {
	ts.templates["minimal"] = &SandboxTemplate{
		Name:             "minimal",
		Version:          "1.0.0",
		Description:      "Minimal sandbox with basic dependencies",
		Image:            "alpine:latest",
		Resources:        defaultResources("100m", "128Mi"),
		Labels:           map[string]string{"agentcube.io/template": "minimal"},
	}

	ts.templates["python"] = &SandboxTemplate{
		Name:             "python",
		Version:          "1.0.0",
		Description:      "Python sandbox with common libraries",
		Image:            "python:3.11-slim",
		Resources:        defaultResources("500m", "512Mi"),
		Environment:      []corev1.EnvVar{{Name: "PYTHONUNBUFFERED", Value: "1"}},
		Labels:           map[string]string{"agentcube.io/template": "python"},
	}

	ts.templates["nodejs"] = &SandboxTemplate{
		Name:             "nodejs",
		Version:          "1.0.0",
		Description:      "Node.js sandbox with npm",
		Image:            "node:20-slim",
		Resources:        defaultResources("500m", "512Mi"),
		Environment:      []corev1.EnvVar{{Name: "NODE_ENV", Value: "development"}},
		Labels:           map[string]string{"agentcube.io/template": "nodejs"},
	}

	ts.templates["go"] = &SandboxTemplate{
		Name:             "go",
		Version:          "1.0.0",
		Description:      "Go development sandbox",
		Image:            "golang:1.21-alpine",
		Resources:        defaultResources("1000m", "1Gi"),
		Environment:      []corev1.EnvVar{{Name: "GO111MODULE", Value: "on"}},
		Labels:           map[string]string{"agentcube.io/template": "go"},
	}

	ts.templates["java"] = &SandboxTemplate{
		Name:             "java",
		Version:          "1.0.0",
		Description:      "Java development sandbox with Maven",
		Image:            "maven:3.9-eclipse-temurin-21-alpine",
		Resources:        defaultResources("1000m", "1Gi"),
		Environment:      []corev1.EnvVar{{Name: "MAVEN_OPTS", Value: "-Xmx512m"}},
		Labels:           map[string]string{"agentcube.io/template": "java"},
	}
}

func defaultResources(cpu, memory string) *corev1.ResourceRequirements {
	return &corev1.ResourceRequirements{
		Limits: corev1.ResourceList{
			corev1.ResourceCPU:    resource.MustParse(cpu),
			corev1.ResourceMemory: resource.MustParse(memory),
		},
		Requests: corev1.ResourceList{
			corev1.ResourceCPU:    resource.MustParse(cpu),
			corev1.ResourceMemory: resource.MustParse(memory),
		},
	}
}

func (ts *TemplateStore) Get(name string) (*SandboxTemplate, error) {
	ts.mu.RLock()
	defer ts.mu.RUnlock()

	template, ok := ts.templates[name]
	if !ok {
		return nil, fmt.Errorf("template not found: %s", name)
	}

	return template, nil
}

func (ts *TemplateStore) List() []*SandboxTemplate {
	ts.mu.RLock()
	defer ts.mu.RUnlock()

	templates := make([]*SandboxTemplate, 0, len(ts.templates))
	for _, t := range ts.templates {
		templates = append(templates, t)
	}

	return templates
}

func (ts *TemplateStore) Create(template *SandboxTemplate) error {
	ts.mu.Lock()
	defer ts.mu.Unlock()

	if template.Name == "" {
		return fmt.Errorf("template name is required")
	}

	if _, exists := ts.templates[template.Name]; exists {
		return fmt.Errorf("template already exists: %s", template.Name)
	}

	if template.Version == "" {
		template.Version = "1.0.0"
	}

	ts.templates[template.Name] = template
	return nil
}

func (ts *TemplateStore) Update(template *SandboxTemplate) error {
	ts.mu.Lock()
	defer ts.mu.Unlock()

	if template.Name == "" {
		return fmt.Errorf("template name is required")
	}

	if _, exists := ts.templates[template.Name]; !exists {
		return fmt.Errorf("template not found: %s", template.Name)
	}

	ts.templates[template.Name] = template
	return nil
}

func (ts *TemplateStore) Delete(name string) error {
	ts.mu.Lock()
	defer ts.mu.Unlock()

	if _, exists := ts.templates[name]; !exists {
		return fmt.Errorf("template not found: %s", name)
	}

	delete(ts.templates, name)
	return nil
}

func (ts *TemplateStore) Validate(name string) error {
	template, err := ts.Get(name)
	if err != nil {
		return err
	}

	if template.Image == "" {
		return fmt.Errorf("template image is required")
	}

	return nil
}

