package templates

import (
	"encoding/json"
	"fmt"
	"net/http"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

type TemplateAPI struct {
	store *TemplateStore
}

func NewTemplateAPI(store *TemplateStore) *TemplateAPI {
	return &TemplateAPI{store: store}
}

func (api *TemplateAPI) RegisterRoutes(r *gin.RouterGroup) {
	r.GET("/templates", api.ListTemplates)
	r.GET("/templates/:name", api.GetTemplate)
	r.POST("/templates", api.CreateTemplate)
	r.PUT("/templates/:name", api.UpdateTemplate)
	r.DELETE("/templates/:name", api.DeleteTemplate)
	r.POST("/templates/:name/validate", api.ValidateTemplate)
}

func (api *TemplateAPI) ListTemplates(c *gin.Context) {
	templates := api.store.List()
	c.JSON(http.StatusOK, gin.H{
		"templates": templates,
		"count":     len(templates),
	})
}

func (api *TemplateAPI) GetTemplate(c *gin.Context) {
	name := c.Param("name")

	template, err := api.store.Get(name)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, template)
}

func (api *TemplateAPI) CreateTemplate(c *gin.Context) {
	var template SandboxTemplate
	if err := c.ShouldBindJSON(&template); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := api.store.Create(&template); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	klog.Infof("Created template: %s", template.Name)
	c.JSON(http.StatusCreated, template)
}

func (api *TemplateAPI) UpdateTemplate(c *gin.Context) {
	name := c.Param("name")

	var template SandboxTemplate
	if err := c.ShouldBindJSON(&template); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	template.Name = name

	if err := api.store.Update(&template); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	klog.Infof("Updated template: %s", name)
	c.JSON(http.StatusOK, template)
}

func (api *TemplateAPI) DeleteTemplate(c *gin.Context) {
	name := c.Param("name")

	if err := api.store.Delete(name); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	klog.Infof("Deleted template: %s", name)
	c.JSON(http.StatusOK, gin.H{"message": "template deleted"})
}

func (api *TemplateAPI) ValidateTemplate(c *gin.Context) {
	name := c.Param("name")

	if err := api.store.Validate(name); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"valid": true, "message": "template is valid"})
}

func (api *TemplateAPI) GetTemplatesJSON() (string, error) {
	templates := api.store.List()
	data, err := json.Marshal(templates)
	if err != nil {
		return "", fmt.Errorf("failed to marshal templates: %w", err)
	}
	return string(data), nil
}

func (api *TemplateAPI) HealthCheck() bool {
	return api.store != nil
}

package main

import (
	"context"
	"flag"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/templates"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(flag.CommandLine)
	flag.Parse()

	port := flag.String("port", "8081", "Port to listen on")
	enableAuth := flag.Bool("enable-auth", false, "Enable authentication")

	klog.Infof("Starting template server on port %s", *port)

	store := templates.NewTemplateStore()
	api := templates.NewTemplateAPI(store)

	r := gin.Default()
	api.RegisterRoutes(r.Group("/api/v1"))

	r.GET("/health", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"status": "healthy",
			"ready":  api.HealthCheck(),
		})
	})

	r.GET("/", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"name":        "AgentCube Template Server",
			"version":     "1.0.0",
			"templates":   len(store.List()),
			"auth_enabled": *enableAuth,
		})
	})

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		<-ctx.Done()
		klog.Info("Shutting down template server...")
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigCh
		klog.Info("Received shutdown signal")
		cancel()
	}()

	server := &http.Server{
		Addr:    ":" + *port,
		Handler: r,
	}

	if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		klog.Exitf("Server error: %v", err)
	}

	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer shutdownCancel()
	server.Shutdown(shutdownCtx)

	klog.Info("Template server stopped")
}

