package main

import (
	"context"
	"flag"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/templates"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(flag.CommandLine)
	flag.Parse()

	port := flag.String("port", "8081", "Port to listen on")
	enableAuth := flag.Bool("enable-auth", false, "Enable authentication")

	klog.Infof("Starting template server on port %s", *port)

	store := templates.NewTemplateStore()
	api := templates.NewTemplateAPI(store)

	r := gin.Default()
	api.RegisterRoutes(r.Group("/api/v1"))

	r.GET("/health", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"status": "healthy",
			"ready":  api.HealthCheck(),
		})
	})

	r.GET("/", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"name":         "AgentCube Template Server",
			"version":      "1.0.0",
			"templates":    len(store.List()),
			"auth_enabled": *enableAuth,
		})
	})

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		<-ctx.Done()
		klog.Info("Shutting down template server...")
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigCh
		klog.Info("Received shutdown signal")
		cancel()
	}()

	server := &http.Server{
		Addr:    ":" + *port,
		Handler: r,
	}

	if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		klog.Exitf("Server error: %v", err)
	}

	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer shutdownCancel()
	server.Shutdown(shutdownCtx)

	klog.Info("Template server stopped")
}

