package ratelimit

import (
	"context"
	"fmt"
	"sync"
	"time"

	"k8s.io/klog/v2"
)

type RateLimiter struct {
	tenants map[string]*TokenBucket
	mu      sync.RWMutex
	config  *Config
}

type TokenBucket struct {
	Tokens     float64
	MaxTokens  float64
	RefillRate float64
	LastRefill time.Time
	mu         sync.Mutex
}

type Config struct {
	DefaultRate       float64
	DefaultBurst      int
	RefillInterval    time.Duration
	EnablePerTenant   bool
}

func NewRateLimiter(config *Config) *RateLimiter {
	if config == nil {
		config = &Config{
			DefaultRate:     100,
			DefaultBurst:    50,
			RefillInterval:  time.Second,
			EnablePerTenant: true,
		}
	}

	return &RateLimiter{
		tenants: make(map[string]*TokenBucket),
		config:  config,
	}
}

func (rl *RateLimiter) Allow(ctx context.Context, tenant string) (bool, error) {
	rl.mu.RLock()
	bucket, exists := rl.tenants[tenant]
	rl.mu.RUnlock()

	if !exists {
		rl.mu.Lock()
		if rl.tenants[tenant] == nil {
			rl.tenants[tenant] = NewTokenBucket(float64(rl.config.DefaultBurst), rl.config.DefaultRate)
		}
		bucket = rl.tenants[tenant]
		rl.mu.Unlock()
	}

	return bucket.TryConsume(1)
}

func (rl *RateLimiter) AllowN(ctx context.Context, tenant string, n int) (bool, error) {
	rl.mu.RLock()
	bucket, exists := rl.tenants[tenant]
	rl.mu.RUnlock()

	if !exists {
		return false, fmt.Errorf("tenant not found: %s", tenant)
	}

	return bucket.TryConsume(float64(n))
}

func (rl *RateLimiter) SetRate(tenant string, rate float64, burst int) error {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	rl.tenants[tenant] = NewTokenBucket(float64(burst), rate)
	klog.Infof("Updated rate limit for tenant %s: rate=%.2f, burst=%d", tenant, rate, burst)

	return nil
}

func (rl *RateLimiter) GetRate(tenant string) (float64, int, error) {
	rl.mu.RLock()
	defer rl.mu.RUnlock()

	bucket, exists := rl.tenants[tenant]
	if !exists {
		return 0, 0, fmt.Errorf("tenant not found: %s", tenant)
	}

	bucket.mu.Lock()
	rate := bucket.RefillRate
	burst := int(bucket.MaxTokens)
	bucket.mu.Unlock()

	return rate, burst, nil
}

func (rl *RateLimiter) RemoveTenant(tenant string) {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	delete(rl.tenants, tenant)
	klog.Infof("Removed rate limit for tenant %s", tenant)
}

func (rl *RateLimiter) ListTenants() []string {
	rl.mu.RLock()
	defer rl.mu.RUnlock()

	tenants := make([]string, 0, len(rl.tenants))
	for tenant := range rl.tenants {
		tenants = append(tenants, tenant)
	}

	return tenants
}

func NewTokenBucket(maxTokens, refillRate float64) *TokenBucket {
	return &TokenBucket{
		Tokens:     maxTokens,
		MaxTokens:  maxTokens,
		RefillRate: refillRate,
		LastRefill: time.Now(),
	}
}

func (tb *TokenBucket) TryConsume(tokens float64) bool {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	tb.refill()

	if tb.Tokens >= tokens {
		tb.Tokens -= tokens
		return true
	}

	return false
}

func (tb *TokenBucket) refill() {
	now := time.Now()
	elapsed := now.Sub(tb.LastRefill).Seconds()

	refillAmount := elapsed * tb.RefillRate
	tb.Tokens = min(tb.Tokens+refillAmount, tb.MaxTokens)
	tb.LastRefill = now
}

func (tb *TokenBucket) AvailableTokens() float64 {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	tb.refill()
	return tb.Tokens
}

func min(a, b float64) float64 {
	if a < b {
		return a
	}
	return b
}

type RateLimitResult struct {
	Allowed    bool
	Remaining  int
	ResetTime  time.Time
	RetryAfter time.Duration
}

func (rl *RateLimiter) CheckLimit(ctx context.Context, tenant string) *RateLimitResult {
	rl.mu.RLock()
	bucket, exists := rl.tenants[tenant]
	rl.mu.RUnlock()

	if !exists {
		return &RateLimitResult{Allowed: true, Remaining: rl.config.DefaultBurst}
	}

	allowed := bucket.TryConsume(1)

	bucket.mu.Lock()
	remaining := int(bucket.Tokens)
	resetTime := bucket.LastRefill.Add(time.Duration(bucket.MaxTokens/bucket.RefillRate) * time.Second)
	bucket.mu.Unlock()

	retryAfter := time.Duration(0)
	if !allowed {
		retryAfter = time.Until(resetTime)
	}

	return &RateLimitResult{
		Allowed:    allowed,
		Remaining:  remaining,
		ResetTime:  resetTime,
		RetryAfter: retryAfter,
	}
}

