package ratelimit

import (
	"context"
	"fmt"
	"sync"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/resource"
	"k8s.io/klog/v2"
)

type QuotaManager struct {
	quotas map[string]*ResourceQuota
	mu     sync.RWMutex
}

type ResourceQuota struct {
	Tenant     string
	CPU        resource.Quantity
	Memory     resource.Quantity
	Sandboxes  int
	UsedCPU    resource.Quantity
	UsedMemory resource.Quantity
	UsedPods   int
}

func NewQuotaManager() *QuotaManager {
	return &QuotaManager{
		quotas: make(map[string]*ResourceQuota),
	}
}

func (qm *QuotaManager) SetQuota(ctx context.Context, tenant string, cpu, memory resource.Quantity, sandboxes int) error {
	qm.mu.Lock()
	defer qm.mu.Unlock()

	qm.quotas[tenant] = &ResourceQuota{
		Tenant:    tenant,
		CPU:       cpu,
		Memory:    memory,
		Sandboxes: sandboxes,
	}

	klog.Infof("Set quota for tenant %s: CPU=%s, Memory=%s, Sandboxes=%d",
		tenant, cpu.String(), memory.String(), sandboxes)

	return nil
}

func (qm *QuotaManager) GetQuota(ctx context.Context, tenant string) (*ResourceQuota, error) {
	qm.mu.RLock()
	defer qm.mu.RUnlock()

	quota, ok := qm.quotas[tenant]
	if !ok {
		return nil, fmt.Errorf("quota not found for tenant: %s", tenant)
	}

	return quota, nil
}

func (qm *QuotaManager) CheckQuota(ctx context.Context, tenant string, cpu, memory resource.Quantity) error {
	qm.mu.RLock()
	quota, ok := qm.quotas[tenant]
	qm.mu.RUnlock()

	if !ok {
		return fmt.Errorf("quota not configured for tenant: %s", tenant)
	}

	newCPU := quota.UsedCPU.Add(cpu)
	newMemory := quota.UsedMemory.Add(memory)

	if newCPU.Cmp(quota.CPU) > 0 {
		return fmt.Errorf("CPU quota exceeded: requested %s, available %s",
			cpu.String(), quota.CPU.Sub(quota.UsedCPU).String())
	}

	if newMemory.Cmp(quota.Memory) > 0 {
		return fmt.Errorf("Memory quota exceeded: requested %s, available %s",
			memory.String(), quota.Memory.Sub(quota.UsedMemory).String())
	}

	return nil
}

func (qm *QuotaManager) CheckSandboxLimit(ctx context.Context, tenant string) error {
	qm.mu.RLock()
	quota, ok := qm.quotas[tenant]
	qm.mu.RUnlock()

	if !ok {
		return nil
	}

	if quota.UsedPods >= quota.Sandboxes {
		return fmt.Errorf("sandbox limit exceeded: current %d, limit %d", quota.UsedPods, quota.Sandboxes)
	}

	return nil
}

func (qm *QuotaManager) Allocate(ctx context.Context, tenant string, cpu, memory resource.Quantity) error {
	qm.mu.Lock()
	defer qm.mu.Unlock()

	quota, ok := qm.quotas[tenant]
	if !ok {
		return fmt.Errorf("quota not found for tenant: %s", tenant)
	}

	quota.UsedCPU.Add(cpu)
	quota.UsedMemory.Add(memory)
	quota.UsedPods++

	klog.V(4).Infof("Allocated resources for tenant %s: CPU=%s, Memory=%s",
		tenant, cpu.String(), memory.String())

	return nil
}

func (qm *QuotaManager) Release(ctx context.Context, tenant string, cpu, memory resource.Quantity) error {
	qm.mu.Lock()
	defer qm.mu.Unlock()

	quota, ok := qm.quotas[tenant]
	if !ok {
		return nil
	}

	quota.UsedCPU.Sub(cpu)
	quota.UsedMemory.Sub(memory)
	quota.UsedPods--

	klog.V(4).Infof("Released resources for tenant %s: CPU=%s, Memory=%s",
		tenant, cpu.String(), memory.String())

	return nil
}

func (qm *QuotaManager) DeleteQuota(ctx context.Context, tenant string) error {
	qm.mu.Lock()
	defer qm.mu.Unlock()

	delete(qm.quotas, tenant)
	klog.Infof("Deleted quota for tenant %s", tenant)

	return nil
}

func (qm *QuotaManager) ListQuotas(ctx context.Context) []*ResourceQuota {
	qm.mu.RLock()
	defer qm.mu.RUnlock()

	quotas := make([]*ResourceQuota, 0, len(qm.quotas))
	for _, quota := range qm.quotas {
		quotas = append(quotas, quota)
	}

	return quotas
}

func (qm *QuotaManager) GetDefaultQuota() *ResourceQuota {
	return &ResourceQuota{
		CPU:       *resource.NewMilliQuantity(4000, resource.DecimalSI),
		Memory:    *resource.NewQuantity(8*1024*1024*1024, resource.BinarySI),
		Sandboxes: 10,
	}
}

func ParseResourceRequirements(reqs corev1.ResourceRequirements) (resource.Quantity, resource.Quantity, error) {
	cpu := resource.Quantity{}
	memory := resource.Quantity{}

	if limits := reqs.Limits; limits != nil {
		if c, ok := limits[corev1.ResourceCPU]; ok {
			cpu = c
		}
		if m, ok := limits[corev1.ResourceMemory]; ok {
			memory = m
		}
	}

	if cpu.IsZero() {
		cpu = *resource.NewMilliQuantity(500, resource.DecimalSI)
	}
	if memory.IsZero() {
		memory = *resource.NewQuantity(512*1024*1024, resource.BinarySI)
	}

	return cpu, memory, nil
}

package workloadmanager

import (
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/ratelimit"
	"k8s.io/klog/v2"
)

type RateLimitMiddleware struct {
	limiter     *ratelimit.RateLimiter
	quotaMgr    *ratelimit.QuotaManager
}

func NewRateLimitMiddleware(limiter *ratelimit.RateLimiter, quotaMgr *ratelimit.QuotaManager) *RateLimitMiddleware {
	return &RateLimitMiddleware{
		limiter:  limiter,
		quotaMgr: quotaMgr,
	}
}

func (m *RateLimitMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		tenant := m.getTenant(c)
		if tenant == "" {
			c.Next()
			return
		}

		result := m.limiter.CheckLimit(c.Request.Context(), tenant)
		if !result.Allowed {
			c.Header("Retry-After", result.RetryAfter.String())
			c.Header("X-RateLimit-Remaining", "0")
			c.Header("X-RateLimit-Reset", result.ResetTime.Format(time.RFC3339))
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error":       "rate limit exceeded",
				"retry_after": result.RetryAfter.String(),
			})
			return
		}

		c.Header("X-RateLimit-Remaining", string(rune(result.Remaining)))
		c.Header("X-RateLimit-Reset", result.ResetTime.Format(time.RFC3339))

		c.Next()
	}
}

func (m *RateLimitMiddleware) CheckQuota(c *gin.Context) {
	tenant := m.getTenant(c)
	if tenant == "" {
		c.Next()
		return
	}

	if err := m.quotaMgr.CheckSandboxLimit(c.Request.Context(), tenant); err != nil {
		c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
			"error": "sandbox limit exceeded",
		})
		return
	}

	c.Next()
}

func (m *RateLimitMiddleware) getTenant(c *gin.Context) string {
	tenant := c.GetHeader("X-Tenant-ID")
	if tenant != "" {
		return tenant
	}

	tenant = c.GetHeader("X-Tenant-Namespace")
	if tenant != "" {
		return tenant
	}

	return c.Param("tenant")
}

func RateLimiterHandler(limiter *ratelimit.RateLimiter, quotaMgr *ratelimit.QuotaManager) gin.HandlerFunc {
	m := NewRateLimitMiddleware(limiter, quotaMgr)
	return func(c *gin.Context) {
		tenant := c.GetHeader("X-Tenant-ID")
		if tenant == "" {
			c.Next()
			return
		}

		result := limiter.CheckLimit(c.Request.Context(), tenant)
		if !result.Allowed {
			klog.Warningf("Rate limit exceeded for tenant %s", tenant)
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error":       "rate limit exceeded",
				"retry_after": result.RetryAfter,
			})
			return
		}

		c.Next()
	}
}

func QuotaMiddleware(quotaMgr *ratelimit.QuotaManager) gin.HandlerFunc {
	return func(c *gin.Context) {
		tenant := c.GetHeader("X-Tenant-ID")
		if tenant == "" {
			c.Next()
			return
		}

		if err := quotaMgr.CheckSandboxLimit(c.Request.Context(), tenant); err != nil {
			klog.Warningf("Quota exceeded for tenant %s: %v", tenant, err)
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error": "quota exceeded",
			})
			return
		}

		c.Next()
	}
}
